import { describe, expect, it } from "vitest";
import { extractObjectOrInterfaceType } from "./extractObjectOrInterfaceType.js";
describe("extractObjectOrInterfaceType", () => {
  const mockClientCtx = {
    ontologyProvider: {
      getObjectDefinition: objectType => {
        if (objectType === "BaseType") {
          return {
            links: {
              testLink1: {
                targetType: "SecondType",
                "multiplicity": "many"
              }
            }
          };
        } else if (objectType === "SecondType") {
          return {
            links: {
              testLink2: {
                targetType: "ThirdType",
                "multiplicity": "many"
              }
            }
          };
        } else if (objectType === "ThirdType") {
          return {
            properties: {
              testProperty: {
                type: "attachment"
              }
            }
          };
        } else {
          throw new Error(`Missing definition for '${objectType}'`);
        }
      },
      getInterfaceDefinition: interfaceType => {
        if (interfaceType === "interface1") {
          return {
            links: {
              linkToInterface2: {
                targetType: "interface",
                targetTypeApiName: "interface2",
                multiplicity: false
              }
            }
          };
        } else if (interfaceType === "interface1") {
          return {
            links: {
              linkToInterface1: {
                targetType: "interface",
                targetTypeApiName: "interface1",
                multiplicity: false
              }
            }
          };
        } else {
          throw new Error(`Missing definition for '${interfaceType}'`);
        }
      }
    }
  };
  const objectSetInterfaceToInterface = {
    type: "interfaceLinkSearchAround",
    objectSet: {
      type: "interfaceBase",
      interfaceType: "interface1"
    },
    interfaceLink: "linkToInterface2"
  };
  it("handles 'withProperties' object set type", async () => {
    const result = await extractObjectOrInterfaceType(mockClientCtx, objectSetInterfaceToInterface);
    expect(result).toEqual({
      apiName: "interface2",
      type: "interface"
    });
  });
  it("handles `intersection` object set type and nested static and reference object sets", async () => {
    const result = await extractObjectOrInterfaceType(mockClientCtx, {
      type: "intersect",
      objectSets: [{
        type: "interfaceLinkSearchAround",
        objectSet: {
          type: "interfaceBase",
          interfaceType: "interface1"
        },
        interfaceLink: "linkToInterface2"
      }, {
        type: "static",
        "objects": ["object1", "object2"]
      }, {
        type: "reference",
        "reference": "rid.os.1234"
      }]
    });
    expect(result).toEqual({
      apiName: "interface2",
      type: "interface"
    });
  });
  it("throws with intersect, subtract, or union having different child object types", async () => {
    await expect(extractObjectOrInterfaceType(mockClientCtx, {
      type: "union",
      objectSets: [{
        type: "interfaceLinkSearchAround",
        objectSet: {
          type: "interfaceBase",
          interfaceType: "interface1"
        },
        interfaceLink: "linkToInterface2"
      }, {
        type: "interfaceBase",
        interfaceType: "interface1"
      }]
    })).rejects.toThrowErrorMatchingInlineSnapshot(`[Error: Invariant failed: Can only have one object type when doing subtract, union]`);
  });
  it("correctly gets the type of the object from narrowToType", async () => {
    const result = await extractObjectOrInterfaceType({
      ...mockClientCtx,
      narrowTypeInterfaceOrObjectMapping: {
        BaseType: "object"
      }
    }, {
      type: "asType",
      entityType: "BaseType",
      objectSet: {
        type: "static",
        objects: ["object1", "object2"]
      }
    });
    expect(result).toEqual({
      apiName: "BaseType",
      type: "object"
    });
  });
});
